#include <stdio.h>
#include <stdlib.h>

// Define the structure for a graph node
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Define the structure for a graph
typedef struct Graph {
    int numNodes;
    Node** adjLists;
} Graph;

// Function to create a new graph node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to create a new graph
Graph* createGraph(int numNodes) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numNodes = numNodes;
    graph->adjLists = (Node**) malloc(numNodes * sizeof(Node*));
    for (int i = 0; i < numNodes; i++) {
        graph->adjLists[i] = NULL;
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    Node* newNode = createNode(dest);
    newNode->next = graph->adjLists[src];
    graph->adjLists[src] = newNode;
}

// Function to perform DFS and topological sorting
void dfs(Graph* graph, int node, int* visited, int* order, int* index) {
    visited[node] = 1;
    Node* temp = graph->adjLists[node];
    while (temp) {
        if (!visited[temp->data]) {
            dfs(graph, temp->data, visited, order, index);
        }
        temp = temp->next;
    }
    order[*index] = node;
    (*index)--;
}

// Function to find the maximum number of ultra-special softwares that can be installed
int findMaxUltraSpecialSoftwares(Graph* graph, int* ultraSpecialSoftwares, int numUltraSpecialSoftwares, int* copiesAvailable) {
    int maxCount = 0;
    int* visited = (int*) malloc(graph->numNodes * sizeof(int));
    int* order = (int*) malloc(graph->numNodes * sizeof(int));
    int index = graph->numNodes - 1;
    for (int i = 0; i < graph->numNodes; i++) {
        if (!visited[i]) {
            dfs(graph, i, visited, order, &index);
        }
    }
    for (int i = 0; i < numUltraSpecialSoftwares; i++) {
        int software = ultraSpecialSoftwares[i];
        int count = 0;
        while (software != -1 && copiesAvailable[software] > 0) {
            copiesAvailable[software]--;
            software = graph->adjLists[software]->data;
            count++;
        }
        if (count > 0) {
            maxCount++;
        }
    }
    return maxCount;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, K;
        scanf("%d %d", &N, &K);
        Graph* graph = createGraph(N);
        for (int i = 0; i < N; i++) {
            int X, Y;
            scanf("%d %d", &X, &Y);
            if (Y != -1) {
                addEdge(graph, X - 1, Y - 1);
            }
        }
        int* copiesAvailable = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &copiesAvailable[i]);
        }
        int* ultraSpecialSoftwares = (int*) malloc(K * sizeof(int));
        for (int i = 0; i < K; i++) {
            scanf("%d", &ultraSpecialSoftwares[i]);
        }
        int maxCount = findMaxUltraSpecialSoftwares(graph, ultraSpecialSoftwares, K, copiesAvailable);
        printf("%d\n", maxCount);
    }
    return 0;
}

