using namespace std;

// Define the structure for a graph node
struct Node {
    int data;
    vector<int> adj;
};

// Define the structure for a graph
struct Graph {
    int numNodes;
    vector<Node> nodes;
};

// Function to create a new graph
Graph createGraph(int numNodes) {
    Graph graph;
    graph.numNodes = numNodes;
    graph.nodes.resize(numNodes);
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph& graph, int src, int dest) {
    graph.nodes[src].adj.push_back(dest);
}

// Function to perform DFS and topological sorting
void dfs(Graph& graph, int node, vector<bool>& visited, vector<int>& order, int& index) {
    visited[node] = true;
    for (int i = 0; i < graph.nodes[node].adj.size(); i++) {
        if (!visited[graph.nodes[node].adj[i]]) {
            dfs(graph, graph.nodes[node].adj[i], visited, order, index);
        }
    }
    order[index--] = node;
}

// Function to find the maximum number of ultra-special softwares that can be installed
int findMaxUltraSpecialSoftwares(Graph& graph, vector<int>& ultraSpecialSoftwares, vector<int>& copiesAvailable) {
    int maxCount = 0;
    vector<bool> visited(graph.numNodes, false);
    vector<int> order(graph.numNodes);
    int index = graph.numNodes - 1;
    for (int i = 0; i < graph.numNodes; i++) {
        if (!visited[i]) {
            dfs(graph, i, visited, order, index);
        }
    }
    for (int i = 0; i < ultraSpecialSoftwares.size(); i++) {
        int software = ultraSpecialSoftwares[i];
        int count = 0;
        while (software != -1 && copiesAvailable[software] > 0) {
            copiesAvailable[software]--;
            software = graph.nodes[software].adj[0];
            count++;
        }
        if (count > 0) {
            maxCount++;
        }
    }
    return maxCount;
}

