            int X, Y;
            cin >> X >> Y;
            if (Y != -1) {
                addEdge(graph, X - 1, Y - 1);
            }
        }
        vector<int> copiesAvailable(N);
        for (int i = 0; i < N; i++) {
            cin >> copiesAvailable[i];
        }
        vector<int> ultraSpecialSoftwares(K);
        for (int i = 0; i < K; i++) {
            cin >> ultraSpecialSoftwares[i];
        }
        int maxCount = findMaxUltraSpecialSoftwares(graph, ultraSpecialSoftwares, copiesAvailable);
        cout << maxCount << endl;
    }
    return 0;
}

